    if (treeContainer) {
        let curr = treeContainer.__vue__;
        while (curr && !curr.list) curr = curr.$parent;
        if (curr && curr.list) return curr;
    }
    // 兼容新版资源管理器状态
    if (typeof explorerState !== 'undefined' && explorerState.originalVue) {
        return explorerState.originalVue;
    }
    return null;
