    async function collapseAllExpandedNodes() {
        // 找到当前活跃的目录树容器
        const treeContainer = document.querySelector('.ant-tree.ant-tree-directory');
        if (!treeContainer) return;

        // 获取所有处于“展开”状态的小箭头
        const openSwitchers = Array.from(treeContainer.querySelectorAll('.ant-tree-switcher_open'));

        if (openSwitchers.length === 0) return; // 如果没有展开的节点，直接放行

        console.log(`🧹 [Search] 准备重置树状态，发现 ${openSwitchers.length} 个展开的节点。`);

        // 倒序遍历点击（从最深层的子节点开始关，最后关最外层）
        for (let i = openSwitchers.length - 1; i >= 0; i--) {
            openSwitchers[i].click();
            // 每次点击后给予极短暂的延迟，让前端框架完成状态更新和动画
            await new Promise(r => setTimeout(r, 50));
        }

        // 额外给树形组件一点点时间彻底完成 DOM 重绘
        await new Promise(r => setTimeout(r, 200));
    }

    async function replayPath(path) {
        let lastClickedElement = null;

        /**
         * 等待某个元素出现在 DOM 中。
         * 返回第一个文本匹配的元素，如果超时则返回 null。
         */
        async function waitForElement(sel, txt, timeoutMs = 10000) {
            const isTreeItem = sel.includes("ant-tree-node-content-wrapper");
            const maxAttempts = Math.ceil(timeoutMs / 100);
            for (let i = 0; i < maxAttempts; i++) {
                for (const node of document.querySelectorAll(sel)) {
                    const nodeText = cleanInnerText(node);
                    if (nodeText === txt || (isTreeItem && nodeText.startsWith(txt))) {
                        return node;
                    }
                }
                await new Promise(r => setTimeout(r, 100));
            }
            // 调试信息
            const allElements = Array.from(document.querySelectorAll(sel)).map(n => ({
                text: cleanInnerText(n),
                rect: n.getBoundingClientRect()
            }));
            console.error(`❌ [Replay] 无法找到 "${txt}" (Selector: ${sel}). 页面中存在的同类元素:`, allElements);
            return null;
        }

        const btn = Array.from(document.querySelectorAll("button span")).find(s => s.innerText.trim() === "开始使用");
        if (btn) { btn.click(); await new Promise(r => setTimeout(r, 500)); }

        for (let stepIndex = 0; stepIndex < path.length; stepIndex++) {
            const step = path[stepIndex];
            const isLastStep = (stepIndex === path.length - 1);
            const isTreeItem = step.selector.includes("ant-tree-node-content-wrapper");
            const isMainMenu = step.selector.includes("div.menu");
            const isFolder = step.selector.includes("div.folderName");

            // --- 处理主菜单和科目文件夹：已激活则跳过 ---
            if (isMainMenu || isFolder) {
                const activeSelector = isMainMenu ? 'div.menu > div.active' : 'div.folderName.active';
                const activeEl = document.querySelector(activeSelector);
                if (activeEl && cleanInnerText(activeEl) === step.text) {
                    console.log(`⚡ [Replay] 跳过已激活的步骤: "${step.text}"`);
                    lastClickedElement = activeEl;
                    continue; // 已经是激活状态，不需要点击
                }
                // 未激活，找到并点击
                const el = await waitForElement(step.selector, step.text);
                if (!el) {
               
                    throw new Error('Replay failed');
                }
                el.click();
                lastClickedElement = el;
                await new Promise(r => setTimeout(r, 300));
                continue;
            }

            // --- 处理树节点 ---
            if (isTreeItem) {
                const el = await waitForElement(step.selector, step.text);
                if (!el) {
               
                    throw new Error('Replay failed');
                }

                if (isLastStep) {
                    // 最终目标节点：始终点击选中
                    el.click();
                    lastClickedElement = el;
                    await new Promise(r => setTimeout(r, 250));
                } else {
                    // 中间节点：检查展开状态，避免 toggle 折叠
                    const treeNode = el.closest('li.ant-tree-treenode');
                    const isExpanded = treeNode &&
                        (treeNode.classList.contains('ant-tree-treenode-switcher-open') ||
                            treeNode.querySelector('.ant-tree-switcher_open') !== null);

                    if (isExpanded) {
                        console.log(`⚡ [Replay] 跳过已展开的节点: "${step.text}"`);
                        lastClickedElement = el;
                    } else {
                        // 节点未展开，点击 switcher 箭头来展开（而不是点击 content-wrapper）
                        const switcher = treeNode ? treeNode.querySelector(':scope > .ant-tree-switcher') : null;
                        if (switcher) {
                            switcher.click();
                        } else {
                            // fallback: 如果找不到 switcher，直接点击 content-wrapper
                            el.click();
                        }
                        lastClickedElement = el;
                        await new Promise(r => setTimeout(r, 300));
                    }
                }
                continue;
            }

            // --- 其他未知类型：直接点击 ---
            const el = await waitForElement(step.selector, step.text);
            if (!el) {
                throw new Error('Replay failed');
            }
            el.click();
            lastClickedElement = el;
            await new Promise(r => setTimeout(r, 250));
        }
        return lastClickedElement;
    } 

