function getActiveQuestionContext() {
    const questions = document.querySelectorAll('.quesContent');
    if (questions.length === 0) return null;
    let activeElement = null;
    const centerY = window.innerHeight / 2;
    let minDistance = Infinity;

    questions.forEach(q => {
        const rect = q.getBoundingClientRect();
        const distance = Math.abs((rect.top + rect.height / 2) - centerY);
        if (distance < minDistance) {
            minDistance = distance;
            activeElement = q;
        }
    });

    if (!activeElement || !activeElement.__vue__) return null;
    const vueInst = activeElement.__vue__;
    return {
        vue: vueInst,
        id: vueInst.data?.id,
        btns: {
            note: Array.from(activeElement.querySelectorAll('button')).find(b => b.innerText.includes('笔记')),
            fav: Array.from(activeElement.querySelectorAll('button')).find(b => b.innerText.includes('收藏'))
        }
    };
}

function initializeAnswerAreaObserver() {


    let sentinelObserver = null;

    let buttonObserver = null;

    // 2. 核心功能：检查并点击按钮（保持不变）

function checkAndClickButtons() {
    const buttons = document.querySelectorAll('button.ant-btn');

    buttons.forEach(btn => {
        const btnText = btn.innerText.trim();

        // 1. 隐藏“放弃补交看答案”按钮
        if (btnText === "放弃补交看答案") {
            btn.style.setProperty('display', 'none', 'important');
            return; // 匹配到了就跳过后续逻辑
        }

            if (btn.innerText.trim().endsWith('答题区') && !btn.classList.contains('ant-btn-primary')) {

                btn.click();

                //btn.style.display = 'none';

                return;

            }

           

        });
        document.querySelectorAll('.tagBox div').forEach(el => {
        if (el.innerText.trim() === '解析') {
            el.style.display = 'none';
        }
    });




    }


    // 3. 启动/停止核心功能的函数（保持不变）

    function startFeature() {

        if (buttonObserver) return;

        checkAndClickButtons();

        buttonObserver = new MutationObserver(checkAndClickButtons);

        buttonObserver.observe(document.querySelector("#app"), { childList: true, subtree: true });

    }

    function stopFeature() {

        if (buttonObserver) {

            buttonObserver.disconnect();

            buttonObserver = null;

        }

    }

    // 4. 新的、更精准的“哨兵”设置函数

    function setupSentinel(contentElement) {

        // 如果已存在哨兵，先断开，以防重复

        if (sentinelObserver) {

            sentinelObserver.disconnect();

        }

        // 创建哨兵，它的任务现在是观察 .content 内部

        sentinelObserver = new MutationObserver(() => {

            if (contentElement.querySelector('.top')) {

                startFeature();

                setupQuickSubmitButtonInHeader();

            } else {

                stopFeature();

            }

        });

        // 启动哨兵

        sentinelObserver.observe(contentElement, { childList: true, subtree: true });

        // 立即检查一次初始状态

        if (contentElement.querySelector('.top')) {

            startFeature();

        } else {

            stopFeature();

        }

    }

    // 5. 创建一个“容器”观察者，它的唯一任务是寻找 .content 元素

    const containerObserver = new MutationObserver(() => {

        const contentEl = document.querySelector('body');

        if (contentEl) {

            // 找到 .content 后，为它设置哨兵

            setupSentinel(contentEl);

            // 任务完成，断开这个容器观察者，因为它是一次性的

            containerObserver.disconnect();

        }

    });

    // 6. 启动流程

    const initialContentEl = document.querySelector('body');

    if (initialContentEl) {

        // 如果 .content 已存在，直接设置哨兵

        setupSentinel(initialContentEl);

    } else {

        // 如果不存在，则启动“容器”观察者去等待它出现

        containerObserver.observe(document.body, { childList: true, subtree: true });

    }

}

function ensureUserInfoPersistence() {
    try {
        const infoString = localStorage.getItem("course_userInfo");
        if (infoString) {
            // 如果 localStorage 有数据但 sessionStorage 没有，则同步过去
            if (!sessionStorage.getItem("course_userInfo")) {
                sessionStorage.setItem("course_userInfo", infoString);
                console.log('✅ 已从存储恢复用户信息至当前会话');
            }
        }
    } catch (e) {
        console.error('[Session Sync] 失败:', e);
    }
}
