function updateTimerUI() {

    if (!timerStartTime) return;

    const pillMenu = document.getElementById('pillMenu');

    const hand = document.getElementById('pill-timer-hand');

    const display = document.getElementById('pill-timer-display');

    // 绝对时间计算，防止缓存和漂移

    const elapsedSeconds = (Date.now() - timerStartTime) / 1000;

    const elapsedMinutes = Math.floor(elapsedSeconds / 60);

    // 1. 更新指针

    const minutesForHand = elapsedMinutes % 60;

    const rotationDegree = minutesForHand * 6; // 360/60 = 6 degrees per minute

    hand.style.transform = `rotate(${rotationDegree}deg)`;

    // 2. 更新展开后的时间显示

    if (elapsedMinutes < 1) {

        display.textContent = '<1 min';

    } else {

        display.textContent = `${elapsedMinutes} min`;

    }

}

function startTimer(startTime) {

    const pillMenu = document.getElementById('pillMenu');

    timerStartTime = startTime;

    pillMenu.classList.add('timer-active');

    // 立即更新一次UI，然后每5秒更新一次

    updateTimerUI();

    if (timerIntervalId) clearInterval(timerIntervalId); // 清除旧的以防万一

    timerIntervalId = setInterval(updateTimerUI, 5000);

}

async function stopTimer() {

    if (!timerIntervalId) return;

    const pillMenu = document.getElementById('pillMenu');

    const timerBtn = document.getElementById('timer-toggle-btn');

    const display = document.getElementById('pill-timer-display');

    // 清除计时器和状态

    clearInterval(timerIntervalId);

    timerIntervalId = null;

    const finalElapsedMinutes = Math.floor((Date.now() - timerStartTime) / 1000 / 60);

    timerStartTime = null;

    await GM_setValue(TIMER_STORAGE_KEY, null);

    // 更新UI到“结束”状态

    pillMenu.classList.remove('timer-active');

    // 1. 临时显示旗子图标

    const originalIconHTML = timerBtn.innerHTML;

    const flagIconHTML = `<svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M4 15s1-1 4-1 5 2 8 2 4-1 4-1V3s-1 1-4 1-5-2-8-2-4 1-4 1z"></path><line x1="4" y1="22" x2="4" y2="15"></line></svg>`;

    timerBtn.innerHTML = flagIconHTML;

    setTimeout(() => { timerBtn.innerHTML = originalIconHTML; }, 2000);

    // 2. 显示最终时间并让其淡出

    display.textContent = `Total: ${finalElapsedMinutes < 1 ? '<1' : finalElapsedMinutes} min`;

    display.classList.add('finished');

    setTimeout(() => {

        display.classList.remove('finished');

        display.style.display = 'none'; // 动画结束后彻底隐藏

    }, 2000);

}

