// --- 修复版：按钮物理引擎 (兼容点击) ---
function applySquishToElement(el) {
    if (el.dataset.physicsAttached) return;
    el.dataset.physicsAttached = "true";

    let isInternalPressing = false;
    const contentArea = document.querySelector('.content');

    const handleDown = (e) => {
         if (e.pointerType === 'mouse') return;
        
        // 只响应左键或触控
        if (e.button !== 0 && e.pointerType === 'mouse') return;

        isInternalPressing = true;
        el.classList.add('ant-btn-squishing');
        if (contentArea) contentArea.classList.add('lock-scroll');
        
        updateTransform(e);
    };

    const updateTransform = (e) => {
        if (!isInternalPressing) return;

        const rect = el.getBoundingClientRect();
        const centerX = rect.left + rect.width / 2;
        const centerY = rect.top + rect.height / 2;
        
        const offX = e.clientX - centerX;
        const offY = e.clientY - centerY;
        
        // 限制平移
        const moveLimit = 2;
        const tx = Math.max(-moveLimit, Math.min(moveLimit, offX * 0.05));
        const ty = Math.max(-moveLimit, Math.min(moveLimit, offY * 0.05));
        
        // 计算拉伸
        const stretchStr = 0.00024 * (settings.lgIntensity || 1);
        const scaleX = 1 + Math.abs(offX) * stretchStr;
        const scaleY = 1 + Math.abs(offY) * stretchStr;
        
        el.style.transform = `translate3d(${tx}px, ${ty}px, 0) scale(${scaleX}, ${scaleY})`;
    };

    const handleUp = () => {
        if (!isInternalPressing) return;
        isInternalPressing = false;
        
        el.classList.remove('ant-btn-squishing');
        if (contentArea) contentArea.classList.remove('lock-scroll');
        
        el.style.transform = ''; // 弹性弹回
    };

    // 绑定事件
    el.addEventListener('pointerdown', handleDown);
    
    // 关键：在 window 上监听移动和抬起，确保手指滑出按钮也能正常回弹
    // 同时不阻止默认事件，让 click 能够正常触发
    const onGlobalMove = (e) => {
        if (isInternalPressing) {
            updateTransform(e);
        }
    };

    window.addEventListener('pointermove', onGlobalMove);
    window.addEventListener('pointerup', handleUp);
    window.addEventListener('pointercancel', handleUp);
}

// 👇 新增：记录当前自阅窗口开启期间是否已弹窗
window.toastShownForCurrentOrBox = false;

