            qs.forEach(q => {
                const r = q.getBoundingClientRect();
                const d = Math.abs((r.top + r.height / 2) - centerY);
                if (d < minD) { minD = d; active = q; }
            });
            if (!active || !active.__vue__) return null;
            return active.__vue__; 
