//app内自动跳转逻辑
function initializePdfFullScreenOpener() {
    let lastHandledPdfUrl = ""; 
    let openLock = false; 

    setInterval(() => {
      
        const iframes = document.querySelectorAll('iframe[src*="/exam/pdf/web/viewer.html"]');
        
        let visibleIframe = null;
        for (let i = 0; i < iframes.length; i++) {
     
            if (iframes[i].src.toLowerCase().includes('.pdf') && iframes[i].offsetParent !== null) {
                visibleIframe = iframes[i];
                break;
            }
        }

        if (visibleIframe) {
            const currentUrl = visibleIframe.src;
            
            
            if (currentUrl !== lastHandledPdfUrl && !openLock) {
                lastHandledPdfUrl = currentUrl;
                
             
                const urlObj = new URL(currentUrl, window.location.origin);
                const fileName = urlObj.searchParams.get('file');
                
                if (!fileName || fileName === '/exam' || fileName.length < 10) {
                    return;
                }

                console.log("检测到有效的 PDF 预览请求:", currentUrl);

                if (appmode === 1) {
                    openLock = true; 
              if (window.AndroidBridge && window.AndroidBridge.openFloatPdf) {
        window.AndroidBridge.openFloatPdf(currentUrl);
    } else {
        window.open(currentUrl, '_blank'); 
    }
               
                    setTimeout(() => {
                        const modalContent = visibleIframe.closest('.ant-modal-content');
                        if (modalContent) {
                            const closeBtn = modalContent.querySelector('.ant-modal-close') || modalContent.querySelector('.ant-modal-close-x');
                            if (closeBtn) closeBtn.click();
                        }
                  
                        setTimeout(() => { openLock = false; }, 1500);
                    }, 300);
                }

              
                const modalContent = visibleIframe.closest('.ant-modal-content');
                if (modalContent) {
                    const header = modalContent.querySelector('.ant-modal-header');
                    if (header && !header.querySelector('.tm-full-screen-pdf')) {
                        const btn = document.createElement('button');
                        btn.className = 'tm-full-screen-pdf ant-btn ant-btn-primary';
                        btn.innerHTML = '全屏预览';
                        btn.style.borderRadius = '30px'; 
                        btn.onclick = (e) => {
                            if (e) e.stopPropagation();
                            window.open(currentUrl, '_blank');
                        };
                        header.appendChild(btn);
                    }
                }
            }
        } else {
         
            if (!openLock) {
                lastHandledPdfUrl = "";
            }
        }
    },800);
}


  

//高考倒计时页面
let todoList = JSON.parse(localStorage.getItem('bdfz_todo_list') || '[]');

function calculateGaokaoDays() {
    const now = new Date();
    const year = now.getFullYear();
    let target = new Date(year, 5, 7);
    if (now > new Date(year, 5, 10)) target = new Date(year + 1, 5, 7);
    if (now >= new Date(year, 5, 7) && now <= new Date(year, 5, 10)) return { days: "000", isExam: true };
    const days = Math.ceil((target - now) / (1000 * 60 * 60 * 24));
    return { days: days.toString().padStart(3, '0'), isExam: false };
}

function renderTodoList() {
    const container = document.getElementById('cd-list-body');
    if (!container) return;
    
    container.innerHTML = todoList.length ? todoList.map((item, index) => `
        <div class="todo-card" data-index="${index}">
            <span style="pointer-events:none;">${item}</span>
        </div>
    `).join('') : '<div style="text-align:center; color:#666; padding:20px;">暂无计划</div>';

    container.querySelectorAll('.todo-card').forEach(card => {
        let startX = 0, currentX = 0, isDragging = false;

        const onStart = (e) => {
            isDragging = true;
            startX = e.type.includes('mouse') ? e.clientX : e.touches[0].clientX;
            card.style.transition = 'none';
        };

        const onMove = (e) => {
            if (!isDragging) return;
            const x = e.type.includes('mouse') ? e.clientX : e.touches[0].clientX;
            currentX = Math.min(0, x - startX);
            card.style.transform = `translateX(${currentX}px)`;
            card.style.opacity = 1 + (currentX / 200);
        };

        const onEnd = () => {
            if (!isDragging) return;
            isDragging = false;
            card.style.transition = 'all 0.3s cubic-bezier(0.2, 0, 0.2, 1)';
            if (currentX < -100) {
                card.style.transform = 'translateX(-150%)';
                card.style.opacity = '0';
                setTimeout(() => {
                    todoList.splice(parseInt(card.dataset.index), 1);
                    localStorage.setItem('bdfz_todo_list', JSON.stringify(todoList));
                    renderTodoList();
                }, 250);
            } else {
                card.style.transform = 'translateX(0)';
                card.style.opacity = '1';
            }
        };

        card.addEventListener('mousedown', onStart);
        card.addEventListener('touchstart', onStart, {passive: true});
     
        const moveHandler = (e) => onMove(e);
        const upHandler = () => {
            if (isDragging) {
                onEnd();
                window.removeEventListener('mousemove', moveHandler);
                window.removeEventListener('mouseup', upHandler);
            }
        };
        window.addEventListener('mousemove', moveHandler);
        window.addEventListener('mouseup', upHandler);
        card.addEventListener('touchmove', onMove, {passive: true});
        card.addEventListener('touchend', onEnd);
    });
}

function openCountdownPlugin() {
    let overlay = document.getElementById('cd-modal-overlay');
    if (!overlay) {
        overlay = document.createElement('div');
        overlay.id = 'cd-modal-overlay';
        overlay.innerHTML = `
            <div id="cd-modal">
                <div class="cd-left">
                    <div class="cd-title">距离高考还剩：</div>
                    <div class="cd-cards" id="cd-digits"></div>
                    <div style="width:100%; text-align:right; font-weight:bold; color:#333;">天</div>
                   <img src="${MASCOT_IMAGE}" class="cd-mascot no-invert">
                </div>
                <div class="cd-right">
                    <div class="cd-title">今日计划</div>
                    <div class="cd-list-container" id="cd-list-body"></div>
                    <div class="cd-btns">
                        <button class="cd-btn" id="cd-add">添加</button>
                        <button class="cd-btn" id="cd-clear">清空</button>
                    </div>
                </div>
            </div>`;
        document.body.appendChild(overlay);
        
      overlay.addEventListener('mousedown', (e) => {
     
            if (!e.target.closest('.todo-card') && !e.target.closest('.cd-btn')) {
                overlay.classList.remove('open');
                if (typeof closeLgModal === 'function') closeLgModal();
            }
        });

        document.getElementById('cd-add').onclick = () => {
            const task = prompt("输入新的计划项目：");
            if (task) { todoList.push(task); localStorage.setItem('bdfz_todo_list', JSON.stringify(todoList)); renderTodoList(); }
        };
        document.getElementById('cd-clear').onclick = () => {
            if(confirm("确定清空吗？")) { todoList = []; localStorage.setItem('bdfz_todo_list', JSON.stringify(todoList)); renderTodoList(); }
        };
    }

    const info = calculateGaokaoDays();
    document.getElementById('cd-digits').innerHTML = info.days.split('').map(d => `
        <div class="cd-digit-card">${d}</div>
    `).join('');

    renderTodoList();
    if (typeof openLgModal === 'function') openLgModal();
    overlay.classList.add('open');
}
